  "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ------------------------------------------------------\n// 1. USERS (The Clients using the Mobile App)\n// ------------------------------------------------------\nmodel User {\n  id                String   @id @default(uuid())\n  email             String   @unique\n  password          String\n  name              String\n  createdAt         DateTime @default(now())\n  profilePictureUrl String?\n\n  // --- PROFILE COMPLETION FIELDS ---\n  sex              String?\n  age              Int?\n  height           Int?\n  weight           Int?\n  goals            String? // JSON string of selected goals e.g. '[\"athletic\",\"lose_weight\"]'\n  profileCompleted Boolean @default(false)\n\n  // --- STRIPE UPDATE ---\n  stripeCustomerId String? @unique\n\n  subscriptions Subscription[]\n  usedCodes     AccessCode[]\n\n  // --- FORUM UPDATE ---\n  posts    Post[]\n  comments Comment[]\n\n  // --- MESSAGING UPDATE ---\n  sentMessages     Message[] @relation(\"SenderUser\")\n  receivedMessages Message[] @relation(\"ReceiverUser\")\n}\n\n// ------------------------------------------------------\n// 2. COACHES (The Admins using the Web Dashboard)\n// ------------------------------------------------------\nmodel Coach {\n  id                String  @id @default(uuid())\n  name              String\n  email             String  @unique\n  password          String\n  specialty         String\n  bio               String?\n  profilePictureUrl String?\n\n  // --- COACH PROFILE UPDATE (Feature 5) ---\n  coverImageUrl String?\n  tagline       String?\n  offerings     String?\n\n  // --- STRIPE UPDATE ---\n  subscriptionPrice Float @default(19.99)\n\n  // Relationships\n  videos          Video[]\n  subscriptions   Subscription[]\n  accessCodes     AccessCode[]\n  recommendations Recommendation[]\n\n  // --- FORUM UPDATE ---\n  posts    Post[]\n  comments Comment[]\n\n  // --- MESSAGING UPDATE ---\n  sentMessages     Message[] @relation(\"SenderCoach\")\n  receivedMessages Message[] @relation(\"ReceiverCoach\")\n}\n\n// ------------------------------------------------------\n// 3. VIDEOS (Uploaded by Coaches)\n// ------------------------------------------------------\nmodel Video {\n  id        String   @id @default(uuid())\n  title     String\n  url       String\n  category  String\n  createdAt DateTime @default(now())\n\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 4. SUBSCRIPTIONS (Links a User to a Coach)\n// ------------------------------------------------------\nmodel Subscription {\n  id     String @id @default(uuid())\n  status String\n\n  stripeSubscriptionId String? @unique\n\n  startDate DateTime @default(now())\n  endDate   DateTime\n\n  userId  String\n  user    User   @relation(fields: [userId], references: [id])\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 5. ACCESS CODES (Given by Coaches to real-life clients)\n// ------------------------------------------------------\nmodel AccessCode {\n  id        String    @id @default(uuid())\n  code      String    @unique\n  usedAt    DateTime?\n  createdAt DateTime  @default(now())\n\n  coachId String\n  coach   Coach   @relation(fields: [coachId], references: [id])\n  usedBy  String?\n  user    User?   @relation(fields: [usedBy], references: [id])\n}\n\n// ------------------------------------------------------\n// 6. RECOMMENDATIONS\n// ------------------------------------------------------\nmodel Recommendation {\n  id        String   @id @default(uuid())\n  type      String\n  content   String\n  createdAt DateTime @default(now())\n\n  coachId String\n  coach   Coach  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 7. POSTS (Forum)\n// ------------------------------------------------------\nmodel Post {\n  id        String   @id @default(uuid())\n  title     String\n  content   String\n  createdAt DateTime @default(now())\n\n  userId  String?\n  user    User?   @relation(fields: [userId], references: [id])\n  coachId String?\n  coach   Coach?  @relation(fields: [coachId], references: [id])\n\n  comments Comment[]\n}\n\n// ------------------------------------------------------\n// 8. COMMENTS\n// ------------------------------------------------------\nmodel Comment {\n  id        String   @id @default(uuid())\n  content   String\n  createdAt DateTime @default(now())\n\n  postId String\n  post   Post   @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  userId  String?\n  user    User?   @relation(fields: [userId], references: [id])\n  coachId String?\n  coach   Coach?  @relation(fields: [coachId], references: [id])\n}\n\n// ------------------------------------------------------\n// 9. MESSAGES (Client <-> Coach DMs)\n// ------------------------------------------------------\nmodel Message {\n  id        String   @id @default(uuid())\n  content   String\n  createdAt DateTime @default(now())\n  read      Boolean  @default(false)\n\n  senderType String // 'user' or 'coach'\n\n  userId  String\n  user    User   @relation(\"SenderUser\", fields: [userId], references: [id])\n  coachId String\n  coach   Coach  @relation(\"SenderCoach\", fields: [coachId], references: [id])\n\n  sentByUserId  String?\n  sentByUser    User?   @relation(\"ReceiverUser\", fields: [sentByUserId], references: [id])\n  sentByCoachId String?\n  sentByCoach   Coach?  @relation(\"ReceiverCoach\", fields: [sentByCoachId], references: [id])\n}\n",
